app.get("/api/stock/:symbol", async (req, res) => {
  try {
    const symbol = req.params.symbol.toUpperCase();

    if (USE_MOCK) {
      return res.json(generateMockData(symbol));
    }

    const data = await yahooFinance.chart(symbol, {
      period1: "2024-01-01",
      interval: "1d",
    });
    const quotes = data.quotes;

    const companyName = data.meta?.shortName || symbol;

    const mappedData = quotes.map((q) => ({
      date: q.date,
      close: q.close,
      volume: q.volume,
    }));

    // Retrieve the current stock price (latest available close price)
    let currentPrice = null;
    if (mappedData.length > 0) {
      currentPrice = mappedData[mappedData.length - 1].close;
    }

    const response = {
      ticker: symbol,
      name: companyName,
      data: mappedData,
      currentPrice: currentPrice,
    };

    console.log(response);
    res.json(response);
  } catch (err) {
    console.error(err);
    res.status(500).send("Error fetching stock data");
  }
});

