const StockChart = ({ data }) => {
  if (!data || !data.data || !data.data.length) return null;

  const company = data.name;
  const ticker = data.ticker;
  const currentPrice = data.currentPrice;
  const formatDateString = (date) => {
    const datePart = date.split("T")[0];
    const monthNumber = parseInt(datePart.split("-")[1], 10);
    const monthAbbr = [
      "Jan",
      "Feb",
      "Mar",
      "Apr",
      "May",
      "Jun",
      "Jul",
      "Aug",
      "Sep",
      "Oct",
      "Nov",
      "Dec",
    ];
    return monthAbbr[monthNumber - 1];
  };

  // Combine labels and values into an array of objects for Recharts
  const chartData = data.data.map((item) => ({
    date: formatDateString(item.date),
    price: item.close,
  }));

  // Add a separate data point for the current price at the end
  const lastDate = chartData.length > 0 ? chartData[chartData.length - 1].date : null;
  const chartDataWithCurrent = lastDate
    ? [
        ...chartData,
        {
          date: lastDate + " (Now)",
          price: null,
          currentPrice: currentPrice,
        },
      ]
    : chartData;

  // For the currentPrice line, fill all previous points with null except the last
  const chartDataFinal = chartDataWithCurrent.map((item, idx) => ({
    ...item,
    currentPrice:
      idx === chartDataWithCurrent.length - 1 ? currentPrice : null,
  }));

  return (
    <div style={{ marginTop: "2rem" }}>
      <h3>
        {company} ({ticker})
      </h3>
      <ResponsiveContainer width="100%" height={300}>
        <LineChart
          data={chartDataFinal}
          margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
        >
          <XAxis dataKey="date" />
          <YAxis domain={["auto", "auto"]} />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="price" stroke="#8884d8" dot={false} />
          <Line
            type="monotone"
            dataKey="currentPrice"
            stroke="#ff7300"
            dot={{ r: 5 }}
            activeDot={{ r: 7 }}
            name="Current Price"
            isAnimationActive={false}
            connectNulls={true}
          />
          <ReferenceLine
            y={currentPrice}
            label={{ value: "Current Price", position: "right", fill: "#ff7300" }}
            stroke="#ff7300"
            strokeDasharray="3 3"
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

